// Process completed call - extract insights and determine follow-up actions

const callData = $input.first().json;

// Parse action items from the call (handle both direct and body-nested structures)
const actionItems = callData.action_items || callData.body?.action_items || (callData.action_items_json ? JSON.parse(callData.action_items_json) : []);
const dynamicVars = callData.dynamic_variables || callData.body?.dynamic_variables || (callData.dynamic_variables_json ? JSON.parse(callData.dynamic_variables_json) : {});

// Determine follow-up type based on call content
let followUpType = 'none';
let followUpPriority = 'low';
let followUpNotes = '';

// Check for booking requests
const bookingKeywords = ['book', 'schedule', 'demo', 'meeting', 'appointment', 'calendar'];
const transcript = (callData.transcript || '').toLowerCase();
const hasBookingIntent = bookingKeywords.some(kw => transcript.includes(kw));

if (hasBookingIntent) {
  followUpType = 'booking';
  followUpPriority = 'high';
  followUpNotes = 'Customer expressed interest in booking';
}

// Check for support issues
const supportKeywords = ['problem', 'issue', 'not working', 'broken', 'help', 'error'];
const hasSupportNeed = supportKeywords.some(kw => transcript.includes(kw));

if (hasSupportNeed) {
  followUpType = 'support';
  followUpPriority = 'high';
  followUpNotes = 'Customer reported an issue';
}

// Check sentiment for escalation
if (callData.customer_sentiment === 'negative' || callData.customer_sentiment === 'frustrated') {
  followUpPriority = 'urgent';
  followUpNotes += ' - Negative sentiment detected';
}

// Build CRM update payload
const crmUpdate = {
  phone: callData.caller_id,
  last_call_date: new Date().toISOString(),
  last_call_duration: callData.call_duration_seconds,
  last_call_summary: callData.call_summary || 'No summary available',
  last_call_sentiment: callData.customer_sentiment,
  interaction_count_increment: 1
};

// Build email payload if follow-up needed
let emailPayload = null;
if (followUpType !== 'none' && dynamicVars.customer_name !== 'there') {
  emailPayload = {
    to: dynamicVars.email || null,
    first_name: dynamicVars.customer_first_name || 'there',
    call_summary: callData.call_summary,
    next_steps: followUpNotes,
    template: 'call-followup'
  };
}

return [{
  json: {
    ...callData,
    processed: true,
    follow_up_type: followUpType,
    follow_up_priority: followUpPriority,
    follow_up_notes: followUpNotes,
    crm_update: crmUpdate,
    email_payload: emailPayload,
    action_items: actionItems,
    dynamic_variables: dynamicVars
  }
}];

// Process failed call - log error and trigger retry logic

const callData = $input.first().json;

// Determine if retry is appropriate
const retryableStatuses = ['timeout', 'network_error', 'service_unavailable'];
const errorType = callData.error_type || callData.body?.error_type || 'unknown';
const shouldRetry = retryableStatuses.includes(errorType);

// Build error log
const errorLog = {
  timestamp: new Date().toISOString(),
  conversation_id: callData.conversation_id,
  caller_id: callData.caller_id,
  error_type: errorType,
  call_duration: callData.call_duration_seconds,
  should_retry: shouldRetry,
  retry_count: (callData.retry_count || 0) + 1
};

// Build notification payload for failed calls
const notification = {
  channel: 'slack',
  message: `Call Failed - Caller: ${callData.caller_id}, Error: ${errorType}, Duration: ${callData.call_duration_seconds}s, Retry: ${shouldRetry ? 'Yes' : 'No'}`,
  priority: shouldRetry ? 'normal' : 'high'
};

return [{
  json: {
    ...callData,
    processed: true,
    error_log: errorLog,
    should_retry: shouldRetry,
    notification: notification,
    follow_up_type: 'error_recovery',
    follow_up_priority: 'high'
  }
}];

// Process abandoned call - short calls where customer hung up

const callData = $input.first().json;
const duration = callData.call_duration_seconds || 0;

// Classify abandonment reason
let abandonReason = 'unknown';
if (duration < 5) {
  abandonReason = 'immediate_hangup';
} else if (duration < 30) {
  abandonReason = 'early_abandonment';
} else {
  abandonReason = 'mid_call_abandonment';
}

// Determine if callback is appropriate
const shouldCallback = duration > 10 && callData.caller_id;

return [{
  json: {
    ...callData,
    processed: true,
    abandon_reason: abandonReason,
    should_callback: shouldCallback,
    follow_up_type: shouldCallback ? 'callback' : 'none',
    follow_up_priority: shouldCallback ? 'medium' : 'low'
  }
}];

const callData = $input.first().json;
const transcript = callData.transcript || '';
if (!transcript || transcript.length < 20) {
  return [{ json: { skip: true, reason: 'Transcript too short for extraction' } }];
}
const agentPrompt = 'You are client, a sales development representative for example Systems. You qualify leads for The 24/7 Filter - an AI-powered after-hours call answering service for small businesses including HVAC, plumbing, property management, and legal services.';
return [{ json: {
  skip: false,
  transcript: transcript,
  agent_system_prompt: agentPrompt,
  extraction_config: {
    categories: [
      {
        category_id: 'sales',
        fields: [
          { field_id: 'deal_stage', type: 'enum', values: ['discovery','qualification','proposal','negotiation','closed_won','closed_lost'], required: true, default_value: 'discovery', prompt: 'What stage of the sales process is this call at? Consider: Did the caller express a specific need? Did they mention budget or timeline? Are they evaluating options?', strictness: 'high' },
          { field_id: 'budget_mentioned', type: 'string', required: false, prompt: 'Extract any budget, price range, or financial constraints mentioned. Include exact figures if stated.', strictness: 'medium' },
          { field_id: 'decision_authority', type: 'enum', values: ['caller','other','unknown'], required: true, default_value: 'unknown', prompt: 'Does the caller have decision-making authority, or do they reference someone else who decides?', strictness: 'medium' },
          { field_id: 'timeline', type: 'string', required: false, prompt: 'Extract any timeline, deadline, or urgency mentioned for making a decision or starting service.', strictness: 'medium' },
          { field_id: 'next_steps', type: 'string', required: false, prompt: 'What next steps were discussed or agreed upon? Include callbacks, follow-ups, or actions.', strictness: 'low' },
          { field_id: 'qualification_status', type: 'enum', values: ['qualified','not_qualified','needs_review'], required: true, default_value: 'needs_review', prompt: 'Based on the full conversation, is this caller a qualified lead? Qualified = expressed need + budget or timeline. Not qualified = no interest, wrong number, spam. Needs review = ambiguous or incomplete information.', strictness: 'medium' },
          { field_id: 'transcript_summary', type: 'string', required: true, default_value: 'No summary available', prompt: 'Generate a concise 2-3 sentence summary of the entire conversation. Include: who called, what they wanted, and the outcome.', strictness: 'low' }
        ],
        context_rules: { default_strictness: 'medium', require_rationale: true, null_behavior: 'return_null_with_rationale' }
      },
      {
        category_id: 'support',
        fields: [
          { field_id: 'issue_type', type: 'string', required: true, prompt: 'What type of issue or request is the caller reporting? Categorize briefly.', strictness: 'medium' },
          { field_id: 'urgency', type: 'enum', values: ['emergency','soon','routine','estimate'], required: true, default_value: 'routine', prompt: 'How urgent is the caller issue? emergency = safety/critical system down. soon = needs quick attention. routine = standard request. estimate = quote/information only.', strictness: 'high' },
          { field_id: 'resolution_status', type: 'enum', values: ['resolved','unresolved','escalated'], required: true, default_value: 'unresolved', prompt: 'Was the issue resolved during the call, left unresolved, or escalated?', strictness: 'high' },
          { field_id: 'escalation_needed', type: 'boolean', required: true, default_value: false, prompt: 'Does this call require escalation to a human agent or specialist?', strictness: 'high' },
          { field_id: 'existing_request', type: 'boolean', required: true, default_value: false, prompt: 'Is this regarding an existing request/ticket? Detection: reference to case/ticket numbers, following up on, checking status of. Default FALSE when unclear.', strictness: 'high' },
          { field_id: 'request_affected_asset', type: 'string', required: false, prompt: 'Extract specific equipment, device, software, or system involved. Include model numbers, asset IDs if stated. Return null when no specific asset mentioned.', strictness: 'medium' },
          { field_id: 'request_deadline', type: 'string', required: false, prompt: 'Extract requestor-specified date or timeframe. Examples: need this fixed by Friday, within 48 hours. Return null when none mentioned.', strictness: 'medium' },
          { field_id: 'request_description', type: 'string', required: false, prompt: 'Generate single factual paragraph (80-120 words) using ONLY explicitly stated information. Inverted-pyramid format. Plain language, active voice. No future commitments.', strictness: 'low' },
          { field_id: 'request_summary', type: 'string', required: false, prompt: 'Generate precise ticket title (<80 chars). Format: [Equipment/Issue] - [Location]. Avoid generic terms like issue, problem. Include equipment ID if provided.', strictness: 'medium' }
        ],
        context_rules: { default_strictness: 'medium', require_rationale: true, null_behavior: 'return_null_with_rationale' }
      },
      {
        category_id: 'external_contacts',
        fields: [
          { field_id: 'requestor_first_name', type: 'string', required: false, prompt: 'Extract first name of person calling from self-introduction. Target phrases: This is [name], My name is [name]. Extract ONLY first name component. Return null if no first name provided.', strictness: 'high' },
          { field_id: 'requestor_last_name', type: 'string', required: false, prompt: 'Extract ONLY last name of person calling. Exclude first names, titles/honorifics. Capture compound surnames completely. Return null when no last name provided.', strictness: 'high' },
          { field_id: 'requestor_company_name', type: 'string', required: false, prompt: 'Extract requestor employer/company name from self-identification phrases. Valid triggers: I am with, calling from, I work for. Critical exclusions: Never extract service provider name from agent greeting, Ignore company being called. Return null when no company affiliation stated.', strictness: 'medium' },
          { field_id: 'contact_phone', type: 'phone', required: false, prompt: 'Extract final confirmed callback phone number in E.164 format (+1XXXXXXXXXX). If user corrected a number, use correction only. Convert number words to digits. Return null if count < 10 digits or no number found.', strictness: 'high' },
          { field_id: 'contact_email', type: 'email', required: false, prompt: 'Extract any email address the caller provides.', strictness: 'high' },
          { field_id: 'contact_preferred_followup_channel', type: 'enum', values: ['phone','sms','email'], required: false, default_value: 'phone', prompt: 'Valid values: phone, sms, email. Detection triggers: call me, text me, send me an email. Default to phone when unclear.', strictness: 'medium' },
          { field_id: 'contact_preferred_followup_time', type: 'string', required: false, prompt: 'Extract follow-up timing preferences. Examples: tomorrow afternoon, after 6 PM only, weekdays before noon. Return null when none mentioned.', strictness: 'medium' },
          { field_id: 'requested_service_address', type: 'string', required: false, prompt: 'Extract physical location WHERE WORK HAPPENS (dispatch destination). NOT the branch being contacted. Return null if no dispatch required or requestor coming to company location.', strictness: 'medium' },
          { field_id: 'requestor_is_contact', type: 'boolean', required: true, default_value: true, prompt: 'Is requestor the designated contact for follow-up? Default: TRUE. Set FALSE only when requestor makes explicit statement designating alternate contact.', strictness: 'high' }
        ],
        context_rules: { default_strictness: 'high', require_rationale: false, null_behavior: 'return_null_with_rationale' }
      },
      {
        category_id: 'internal_contacts',
