          { field_id: 'requested_person', type: 'string', required: false, prompt: 'Name of specific person requestor asks to speak with. Return null if no specific person requested by name.', strictness: 'high' },
          { field_id: 'department', type: 'enum', values: ['Service','Field Service','Sales','Marketing','Purchasing','Fulfillment','Shipping','Billing','Finance','Accounting','HR','Payroll','IT','IT Support','Operations','Contracts','Administration','General'], required: true, default_value: 'General', prompt: 'EXACTLY one from allowed values. Default General when unclear.', strictness: 'high' },
          { field_id: 'transfer_reason', type: 'string', required: false, prompt: 'Short summary (<=120 chars) explaining WHY transferred. Return null if no transfer.', strictness: 'low' },
          { field_id: 'conversation_transferred', type: 'boolean', required: true, default_value: false, prompt: 'Was conversation transferred to live person? Set TRUE only when actual transfer mechanism invoked. Default FALSE.', strictness: 'high' },
          { field_id: 'transfer_destination', type: 'string', required: false, prompt: 'If transferred, capture destination label. Examples: Main operator, Billing department. Return null if no transfer.', strictness: 'medium' }
        ],
        context_rules: { default_strictness: 'medium', require_rationale: false, null_behavior: 'return_null_with_rationale' }
      },
      {
        category_id: 'external_company',
        fields: [
          { field_id: 'company_industry', type: 'string', required: false, prompt: 'What industry does the caller company operate in?', strictness: 'medium' },
          { field_id: 'company_size', type: 'string', required: false, prompt: 'Extract any mention of company size (employees, revenue, locations).', strictness: 'medium' },
          { field_id: 'company_location', type: 'string', required: false, prompt: 'Extract the caller company location (city, state, region).', strictness: 'medium' }
        ],
        context_rules: { default_strictness: 'medium', require_rationale: false, null_behavior: 'return_null_with_rationale' }
      },
      {
        category_id: 'internal_company',
        fields: [
          { field_id: 'site_location', type: 'string', required: false, prompt: 'Site or branch location for internal routing. Return null if none mentioned.', strictness: 'medium' },
          { field_id: 'service_area', type: 'string', required: false, prompt: 'What service area or product line does this call relate to?', strictness: 'medium' },
          { field_id: 'account_status', type: 'enum', values: ['active','inactive','prospect','churned'], required: true, default_value: 'prospect', prompt: 'What is the caller account status? Are they an existing customer, prospect, or former customer?', strictness: 'high' }
        ],
        context_rules: { default_strictness: 'medium', require_rationale: false, null_behavior: 'return_null_with_rationale' }
      }
    ],
    global_context: { agent_identity: 'client - example Lead Specialist', business_domain: 'AI-powered after-hours call answering for SMBs' }
  },
  metadata: { conversation_id: callData.conversation_id, agent_id: callData.agent_id }
} }];

const input = $input.first().json;
const fields = input.fields || [];
const meta = {
  extraction_id: input.extraction_id || '',
  conversation_id: input.conversation_id || $('Prepare Extraction Input').first().json.metadata?.conversation_id || '',
  timestamp: input.timestamp || new Date().toISOString(),
  model: input.model || '',
  categories_processed: input.categories_processed || 0,
  errors_count: (input.errors || []).length,
};
const row = { ...meta };
for (const f of fields) {
  const key = f.category + '__' + f.field_id;
  row[key] = String(f.value ?? '');
}
row.raw_envelope = JSON.stringify(input);
return [{ json: row }];
